import { describe, expect, test } from 'bun:test';
import { CustomSrp, modPow, SRP_g, SRP_N } from './srp.ts';

/**
 * Golden vectors generated by running the Python reference implementation
 * with a pinned `a` and synthetic server response. Source script:
 * /tmp/aula_srp_vectors.py — invoke under a venv with pycryptodome, then
 * paste the output here. Re-pin only when the algorithm changes.
 */
const VECTORS = {
  pinnedA: BigInt('0xaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa'),
  expectedAHex:
    '',
  srpSaltHex: 'abababababababababababababababababababababababababababababababab',
  randomBHex: '132e1c7aa9d0b2f2946123eba34836865d2f25cf2f22318ac55865fa3c910cb4f27678fa72f49da0',
  passwordHex: 'cdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcdcd',
  authSessionId: 'test-session-uuid-12345',
  expectedM1: 'b17f22a30c3bf99168221d10f18f5c6b7d858c63f4bb85beecc80155ed013343',
  expectedKHex: 'b092dc185d90bd046d8e8a8314acddcea332af32a6abb662e9f8ca92d47d1046',
  expectedM2: 'c8906d7dc6fcda339cc47d73f4626292a0a6dc819cafa261e311e733f3faa570',
};

describe('CustomSrp constants', () => {
  test('N is 3072 bits and matches the Aula prime', () => {
    // The reverse-engineering brief called this "2048-bit" but the actual
    // value in CustomSRP.py is 3072 bits.
    expect(SRP_N.toString(2).length).toBe(3072);
    expect(SRP_N.toString(16).startsWith('db96e5d0bcad')).toBe(true);
  });

  test('g = 2', () => {
    expect(SRP_g).toBe(2n);
  });
});

describe('modPow', () => {
  test('matches BigInt ** for small inputs', () => {
    expect(modPow(7n, 3n, 1000n)).toBe(7n ** 3n % 1000n);
  });

  test('handles negative bases by normalizing into [0, mod)', () => {
    expect(modPow(-3n, 1n, 11n)).toBe(8n);
  });

  test('mod 1 returns 0', () => {
    expect(modPow(123n, 456n, 1n)).toBe(0n);
  });
});

describe('CustomSrp golden vectors (vs Python reference)', () => {
  test('stage1 produces the expected A hex for a pinned `a`', () => {
    const srp = new CustomSrp({ a: VECTORS.pinnedA });
    expect(srp.stage1()).toBe(VECTORS.expectedAHex);
  });

  test('stage3 produces the expected M1 and K', () => {
    const srp = new CustomSrp({ a: VECTORS.pinnedA });
    srp.stage1();
    const { m1Hex, K } = srp.stage3({
      srpSaltHex: VECTORS.srpSaltHex,
      randomBHex: VECTORS.randomBHex,
      passwordHex: VECTORS.passwordHex,
      authSessionId: VECTORS.authSessionId,
    });
    expect(m1Hex).toBe(VECTORS.expectedM1);
    expect(K.toString('hex')).toBe(VECTORS.expectedKHex);
  });

  test('stage5 accepts the matching server M2 and rejects others', () => {
    const srp = new CustomSrp({ a: VECTORS.pinnedA });
    srp.stage1();
    srp.stage3({
      srpSaltHex: VECTORS.srpSaltHex,
      randomBHex: VECTORS.randomBHex,
      passwordHex: VECTORS.passwordHex,
      authSessionId: VECTORS.authSessionId,
    });
    expect(srp.stage5(VECTORS.expectedM2)).toBe(true);
    expect(srp.stage5('00'.repeat(32))).toBe(false);
  });
});

describe('CustomSrp safety checks', () => {
  test('stage3 rejects B = 0', () => {
    const srp = new CustomSrp({ a: VECTORS.pinnedA });
    srp.stage1();
    expect(() =>
      srp.stage3({
        srpSaltHex: VECTORS.srpSaltHex,
        randomBHex: '00',
        passwordHex: VECTORS.passwordHex,
        authSessionId: VECTORS.authSessionId,
      }),
    ).toThrow();
  });

  test('stage5 throws if called before stage3', () => {
    const srp = new CustomSrp({ a: VECTORS.pinnedA });
    expect(() => srp.stage5('00'.repeat(32))).toThrow();
  });
});

describe('CustomSrp authEnc/authDec roundtrip', () => {
  test('encrypt → decrypt with K', () => {
    const srp = new CustomSrp({ a: VECTORS.pinnedA });
    srp.stage1();
    srp.stage3({
      srpSaltHex: VECTORS.srpSaltHex,
      randomBHex: VECTORS.randomBHex,
      passwordHex: VECTORS.passwordHex,
      authSessionId: VECTORS.authSessionId,
    });
    const blob = srp.authEnc(Buffer.from('hello mitid app', 'utf8'));
    const b64 = blob.toString('base64');
    expect(srp.authDec(b64).toString('utf8')).toBe('hello mitid app');
  });
});
